INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (126401, "2023/09/22 14:59:59", 0.0, 1.47, "クローチェ", 1, 10001, 2002, 2, 1, "2023/06/30 12:00:00", 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (126401, "2023/09/22 14:59:59", 0.0, 2.15, "クローチェ", 2, 10002, 2002, 1, 2, "2023/06/30 12:00:00", 1, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (126501, "2023/09/22 14:59:59", 0.0, 0.0, "ライラエル", 1, 10003, 2002, 2, 2, "2023/06/30 12:00:00", 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (126501, "2023/09/22 14:59:59", 0.0, 0.0, "ライラエル", 2, 10004, 2002, 1, 1, "2023/06/30 12:00:00", 1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (127702, "2023/12/22 14:59:59", 0.0, 0.0, "リンド", 1, 10005, 2002, 2, 2, "2023/09/15 15:00:00", 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (127702, "2023/12/22 14:59:59", 0.0, 0.0, "リンド", 2, 10006, 2002, 2, 2, "2023/09/15 15:00:00", 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (127802, "2023/12/22 14:59:59", 0.0, 0.0, "ヴルム", 1, 10007, 2002, 1, 1, "2023/09/15 15:00:00", 2, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (127802, "2023/12/22 14:59:59", 0.0, 6.5, "ヴルム", 2, 10008, 2002, 1, 2, "2023/09/15 15:00:00", 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (129602, "2024/03/22 14:59:59", 0.0, 0.0, "アネモネ", 1, 10009, 2002, 1, 2, "2023/12/15 15:00:00", 3, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (129602, "2024/03/22 14:59:59", 0.0, 0.0, "アネモネ", 2, 10010, 2002, 1, 2, "2023/12/15 15:00:00", 3, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (129701, "2024/03/22 14:59:59", 0.0, 0.0, "ネフィ=ネラ", 1, 10011, 2002, 1, 1, "2023/12/15 15:00:00", 3, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (129701, "2024/03/22 14:59:59", 0.0, 6.2, "ネフィ=ネラ", 2, 10012, 2002, 1, 2, "2023/12/15 15:00:00", 3, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130301, "2024/06/22 14:59:59", 0.0, 3.1, "カノン", 1, 10013, 2002, 5, 3, "2024/03/15 15:00:00", 4, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130301, "2024/06/22 14:59:59", 0.0, 6.15, "カノン", 2, 10014, 2002, 2, 3, "2024/03/15 15:00:00", 4, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130401, "2024/06/22 14:59:59", 0.0, 0.0, "ナーナ", 1, 10015, 2002, 2, 2, "2024/03/15 15:00:00", 4, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130401, "2024/06/22 14:59:59", 0.0, 3.35, "ナーナ", 2, 10016, 2002, 1, 2, "2024/03/15 15:00:00", 4, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130502, "2024/09/22 14:59:59", 0.0, 0.0, "ホウオウ", 1, 10017, 2002, 1, 1, "2024/06/15 15:00:00", 5, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130502, "2024/09/22 14:59:59", 0.0, 3.18, "ホウオウ", 2, 10018, 2002, 1, 2, "2024/06/15 15:00:00", 5, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130503, "2024/09/22 14:59:59", 0.0, 0.0, "ホウオウ", 3, 10019, 2002, 4, 4, "2024/06/15 15:00:00", 5, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (123301, "2024/09/22 14:59:59", 0.0, 4.9, "ネア", 1, 10020, 2002, 2, 1, "2024/06/15 15:00:00", 5, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (123301, "2024/09/22 14:59:59", 0.0, 4.8, "ネア", 2, 10021, 2002, 2, 1, "2024/06/15 15:00:00", 5, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133301, "2024/12/22 14:59:59", 0.0, 4.922, "カリザ", 1, 10022, 2002, 1, 3, "2024/09/15 15:00:00", 6, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133301, "2024/12/22 14:59:59", 0.0, 9.638, "カリザ", 2, 10023, 2002, 5, 3, "2024/09/15 15:00:00", 6, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133401, "2024/12/22 14:59:59", 0.0, 2.88, "ミーア", 1, 10024, 2002, 2, 1, "2024/09/15 15:00:00", 6, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133401, "2024/12/22 14:59:59", 0.0, 4.818, "ミーア", 2, 10025, 2002, 1, 5, "2024/09/15 15:00:00", 6, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133002, "2025/03/22 14:59:59", 0.0, 1.78, "グレイス", 1, 10026, 2002, 1, 2, "2024/12/15 15:00:00", 7, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133002, "2025/03/22 14:59:59", 0.0, 6.15, "グレイス", 2, 10027, 2002, 7, 1, "2024/12/15 15:00:00", 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133102, "2025/03/22 14:59:59", 0.0, 4.28, "ヴァイオレット", 1, 10028, 2002, 2, 6, "2024/12/15 15:00:00", 7, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (133102, "2025/03/22 14:59:59", 0.0, 0.0, "ヴァイオレット", 2, 10029, 2002, 1, 1, "2024/12/15 15:00:00", 7, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (136902, "2025/06/23 14:59:59", 0.0, 5.53, "ルルィ", 1, 10030, 2002, 1, 2, "2025/03/15 15:00:00", 8, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (136902, "2025/06/23 14:59:59", 0.0, 6.05, "ルルィ", 2, 10031, 2002, 7, 9, "2025/03/15 15:00:00", 8, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (137001, "2025/06/23 14:59:59", 0.0, 0.0, "デュラン", 1, 10032, 2002, 1, 2, "2025/03/15 15:00:00", 8, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (137001, "2025/06/23 14:59:59", 0.0, 0.0, "デュラン", 2, 10033, 2002, 1, 2, "2025/03/15 15:00:00", 8, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135902, "2025/09/23 14:59:59", 0.0, 0.0, "サツキ", 1, 10034, 2002, 2, 2, "2025/06/16 15:00:00", 9, "おう\n好きなもん持ってきな", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135902, "2025/09/23 14:59:59", 0.0, 4.935, "サツキ", 2, 10035, 2002, 6, 1, "2025/06/16 15:00:00", 9, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135802, "2025/09/23 14:59:59", 0.0, 7.441, "ユキノ", 1, 10036, 2002, 5, 2, "2025/06/16 15:00:00", 9, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135802, "2025/09/23 14:59:59", 0.0, 0.0, "ユキノ", 2, 10037, 2002, 7, 7, "2025/06/16 15:00:00", 9, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130901, "2025/12/22 14:59:59", 0.0, 2.295, "クルル", 1, 10038, 2002, 2, 2, "2025/09/16 15:00:00", 10, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (130901, "2025/12/22 14:59:59", 0.0, 6.281, "クルル", 2, 10039, 2002, 6, 1, "2025/09/16 15:00:00", 10, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (137701, "2025/12/22 14:59:59", 0.0, 5.549, "ヴォルガーノ", 1, 10040, 2002, 1, 2, "2025/09/16 15:00:00", 10, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (137701, "2025/12/22 14:59:59", 0.0, 2.64, "ヴォルガーノ", 2, 10041, 2002, 6, 3, "2025/09/16 15:00:00", 10, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (132801, "2026/03/23 11:59:59", 0.0, 7.642, "ライラエル", 1, 10042, 2002, 4, 7, "2025/12/15 15:00:00", 11, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (132802, "2026/03/23 11:59:59", 0.0, 0.0, "ライラエル", 2, 10043, 2002, 1, 1, "2025/12/15 15:00:00", 11, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (134502, "2026/03/23 11:59:59", 0.0, 0.0, "クローチェ", 1, 10044, 2002, 1, 1, "2025/12/15 15:00:00", 11, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (134501, "2026/03/23 11:59:59", 0.0, 3.72, "クローチェ", 2, 10045, 2002, 1, 2, "2025/12/15 15:00:00", 11, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (138201, "2026/06/22 11:59:59", 0.0, 4.991, "ネフィ＝ネラ", 1, 10046, 2002, 1, 2, "2026/03/16 12:00:00", 12, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (138201, "2026/06/22 11:59:59", 0.0, 3.877, "ネフィ＝ネラ", 2, 10047, 2002, 4, 1, "2026/03/16 12:00:00", 12, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (136001, "2026/06/22 11:59:59", 0.0, 1.71, "アラクネ", 1, 10048, 2002, 6, 4, "2026/03/16 12:00:00", 12, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (136001, "2026/06/22 11:59:59", 0.0, 5.32, "アラクネ", 2, 10049, 2002, 2, 5, "2026/03/16 12:00:00", 12, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135401, "2026/09/22 11:59:59", 0.0, 3.727, "アネモネ", 1, 10050, 2002, 4, 9, "2026/06/15 12:00:00", 13, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135401, "2026/09/22 11:59:59", 0.0, 7.213, "アネモネ", 2, 10051, 2002, 9, 7, "2026/06/15 12:00:00", 13, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135301, "2026/09/22 11:59:59", 0.0, 1.874, "クリア", 1, 10052, 2002, 2, 1, "2026/06/15 12:00:00", 13, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", -470.0);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES (135301, "2026/09/22 11:59:59", 0.0, 0.0, "クリア", 2, 10053, 2002, 2, 2, "2026/06/15 12:00:00", 13, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", -470.0);
